window.PAPERNOTE_DATA={"generated_at":"2026-07-23T20:13:02+08:00","counts":{"papers":15,"weeks":2,"themes":4,"viewpoints":4,"cached":15},"weeks":[{"id":"2026-W30","label":"2026-W30","count":7},{"id":"2026-W29","label":"2026-W29","count":8}],"themes":[{"id":"agent-security","label":"智能体与大模型安全","count":9},{"id":"mobile-security","label":"移动与身份安全","count":3},{"id":"application-security","label":"应用与协议安全","count":2},{"id":"systems-security","label":"系统、固件与侧信道","count":1}],"papers":[{"id":"arxiv-2607-17986-self-state-attacks","title":"Self-State Attacks on Self-Hosted AI Agents: How Far Can OS Defenses Go?","normalized_title":"self state attacks on self hosted ai agents how far can os defenses go","authors":["Yimeng Chen","Nathanael Denis","Roberto Di Pietro","Jurgen Schmidhuber"],"venues":["arXiv"],"status":"preprint-unreviewed","doi":null,"arxiv_id":"2607.17986","urls":["https://arxiv.org/abs/2607.17986"],"first_seen":"2026-07-21","last_updated":"2026-07-21","topics":["agent-security","self-hosted-agent","operating-system-security","persistent-state"],"weekly_notes":["weekly/2026/2026-W30.md"],"week":"2026-W30","theme":"agent-security","theme_label":"智能体与大模型安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W30.md","week":"2026-W30","direction":"智能体安全 / 主机与状态完整性","keywords":"自托管智能体、自状态攻击、操作系统防御、文件完整性、备份恢复","author_affiliations":"阿卜杜拉国王科技大学生成式人工智能卓越中心：Yimeng Chen、Nathanaël Denis、Roberto Di Pietro、Jürgen Schmidhuber；瑞士人工智能实验室 IDSIA-USI/SUPSI：Jürgen Schmidhuber","venue_status":"arXiv｜预印","public_date":"2026-07-20 公开","original_links":[{"label":"arXiv 原文","url":"https://arxiv.org/abs/2607.17986"}],"question":"自托管智能体为了学习和适应，必须合法读写自己的记忆、指令与配置；攻击者污染这些文件时，往往也使用相同的文件写入机制。如果恶意更新与正常适应在操作系统层表现为相同系统调用，那么传统访问控制和文件监控能识别多少攻击，又有哪些风险必须依赖更高层语义才能判断，是论文试图划定的防御边界。","method":"论文用“目标、机制、粒度、时间”四个维度组织自状态攻击空间，在一个代表性自托管智能体上构造 23 类攻击单元和 43 个真实文件操作。作者采集编程、研究、运维和通用四类工作负载轨迹，再比较访问控制、文件完整性监测、基于工作负载的异常检测以及备份恢复。","method_example":"智能体为了记录用户偏好，可能合法地向记忆文件追加一句话；攻击者也可能通过同一次写入接口追加一条改变工具权限的指令。只看“哪个进程写了哪个文件”，两次操作可能非常相似。论文的方法会先按指令、配置和可变记忆区分保护目标，再用正常工作负载建立写入行为基线，对异常修改告警，并用快照保证受污染状态可以回滚。","evidence":"在每个工作负载和攻击条件重复 30 次后，23 类攻击中有 11 类在操作系统层可见、8 类仅在特定条件下可见、4 类无法区分。全量文件完整性监测的真正率为 100%，但合法写入的逐事件误报率达到 0.76—0.99；按工作负载建模后，误报率降至 0.08—0.36，仍会漏掉与正常记忆写入高度重叠的小改动。","limitations":"研究只测试一个智能体实现和四类工作负载；数据较少的行为模型仍有较高误报率；操作系统事件无法理解文件内容的语义，因此不能判断一次合法写入究竟是在学习还是在污染状态。","practice":"应把指令、配置和可变记忆分层保护：前两者尽量只读或通过受控流程更新，记忆层结合工作负载监控与可回滚快照。文件权限或完整性监测都不能单独解决语义等价写入问题。","recommendation":"论文用经典主机安全机制解释智能体自修改风险，有助于把长期记忆研究转化为可部署的系统防御方案。"},"primary_url":"https://arxiv.org/abs/2607.17986"},{"id":"usenix-sec26-chang-retrieval-barrier","title":"Overcoming the Retrieval Barrier: Indirect Prompt Injection in the Wild for LLM Systems","normalized_title":"overcoming the retrieval barrier indirect prompt injection in the wild for llm systems","authors":["Hongyan Chang","Ergute Bao","Xinjian Luo","Ting Yu"],"venues":["USENIX Security 2026"],"status":"accepted-prepublication","doi":null,"arxiv_id":null,"urls":["https://www.usenix.org/conference/usenixsecurity26/presentation/chang-hongyan","https://www.usenix.org/system/files/conference/usenixsecurity26/sec26_prepub_chang.pdf","https://zenodo.org/records/17968523"],"first_seen":"2026-07-21","last_updated":"2026-07-21","topics":["agent-security","rag-security","indirect-prompt-injection","retrieval-poisoning"],"weekly_notes":["weekly/2026/2026-W30.md"],"week":"2026-W30","theme":"agent-security","theme_label":"智能体与大模型安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W30.md","week":"2026-W30","direction":"智能体安全 / 检索增强生成安全","keywords":"间接提示注入、检索屏障、向量嵌入、黑盒优化、工具调用","author_affiliations":"穆罕默德·本·扎耶德人工智能大学：Hongyan Chang、Ergute Bao、Xinjian Luo、Ting Yu","venue_status":"USENIX Security 2026｜接收","public_date":"截至 2026-07-21，官方会前原文可访问","original_links":[{"label":"会议官方页面","url":"https://www.usenix.org/conference/usenixsecurity26/presentation/chang-hongyan"},{"label":"官方会前原文","url":"https://www.usenix.org/system/files/conference/usenixsecurity26/sec26_prepub_chang.pdf"}],"question":"间接提示注入通常假设恶意文档已经进入大语言模型的上下文，但现实系统会先用检索器筛选文档。攻击文本即使能够操纵模型，如果与用户查询的语义相似度不够，也可能永远不会被取回。论文要解决的是：攻击者只能写入一个语料条目、只能调用黑盒向量嵌入接口时，如何让承载恶意指令的文档稳定越过检索屏障，并最终影响智能体行为。","method":"作者把注入文档拆成两部分：一部分承载攻击目标，另一部分是提高查询相似度的短触发片段。随后用交叉熵方法在离散词元空间中反复采样、评分和更新触发片段，从而在不知道嵌入模型内部参数的情况下优化检索排名。贡献在于把攻击从“模型已读到恶意文本”的局部假设，扩展为查询、检索、阅读和执行组成的端到端链路。","method_example":"假设攻击者希望用户询问“如何配置 SSH 密钥”时，系统检索到一封带有外泄指令的恶意邮件。单纯插入恶意指令可能与该问题不够相似；论文方法会保留邮件中的攻击内容，同时自动搜索一段与目标查询高度相似的短前缀，将两者拼接后写入语料库，使该邮件更可能进入检索结果，再由后续提示注入诱导智能体执行命令。","evidence":"论文覆盖 11 个信息检索基准和 8 个开源或闭源嵌入模型，报告的检索成功率接近 100%；针对 OpenAI 嵌入接口构造一个目标查询的最低成本约为 0.21 美元。在合成邮件和多智能体工作流中，一封毒化邮件使 GPT-4o 执行 SSH 密钥外泄脚本的成功率超过 80%。","limitations":"实验主要针对基于向量嵌入的检索，没有系统覆盖混合检索和重排器；不同架构嵌入模型之间的迁移效果不稳定；端到端实验使用公开基准和合成语料，不能等同于已经攻破真实生产系统。","practice":"检索层不能只依赖相似度和前若干项结果。工程上应隔离外部写入源的权限与来源，并在检索后继续保留内容信任标记、工具调用授权和敏感数据出站控制。","recommendation":"它把间接提示注入研究推进到完整的“查询—检索—执行”链路，论文状态明确、实验覆盖较广，是本期最值得复现的一篇。"},"primary_url":"https://www.usenix.org/conference/usenixsecurity26/presentation/chang-hongyan"},{"id":"issta26-chen-insecure-memory","title":"Insecure Coding Preferences in Long-Term Memory: Security Risks for LLM-based Code Generation","normalized_title":"insecure coding preferences in long term memory security risks for llm based code generation","authors":["Yuchen Chen","Wei Cheng","Yuan Xiao","Zhou Yang","Weifeng Sun","Chunrong Fang","Xiang Chen","Baowen Xu","David Lo","Zhenyu Chen"],"venues":["ISSTA 2026"],"status":"accepted","doi":null,"arxiv_id":"2607.17619","urls":["https://arxiv.org/abs/2607.17619","https://conf.researchr.org/track/issta-2026/issta-2026-research-papers"],"first_seen":"2026-07-21","last_updated":"2026-07-21","topics":["application-security","agent-memory","secure-code-generation","llm-security"],"weekly_notes":["weekly/2026/2026-W30.md"],"week":"2026-W30","theme":"agent-security","theme_label":"智能体与大模型安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W30.md","week":"2026-W30","direction":"应用安全 / 安全代码生成","keywords":"长期记忆、不安全偏好、代码生成、漏洞评测、安全过滤","author_affiliations":"南京大学：Yuchen Chen、Yuan Xiao、Chunrong Fang、Baowen Xu、Zhenyu Chen；南京航空航天大学：Wei Cheng；阿尔伯塔大学及阿尔伯塔机器智能研究院：Zhou Yang；新加坡管理大学：Weifeng Sun、David Lo；南通大学：Xiang Chen","venue_status":"ISSTA 2026｜接收","public_date":"arXiv 版本于 2026-07-20 公开","original_links":[{"label":"arXiv 原文","url":"https://arxiv.org/abs/2607.17619"}],"question":"代码助手会把用户偏好写入长期记忆，并在之后的独立会话中重复使用。某些偏好起初可能只是为了调试方便、兼容旧系统或快速通过测试，但其中可能隐含弱随机数、硬编码凭据或不安全解析等模式。论文研究这些不安全偏好是否会跨任务持续影响代码生成，以及模型给出安全警告、遵循显式安全要求和保持功能正确性之间存在怎样的权衡。","method":"作者在 ChatGPT、Gemini、Qwen 和 Grok 上，针对 SALLM 的 100 个 Python 任务以及 CWEval 的 94 个其他语言任务，构造与常见弱点枚举相对应的不安全偏好记忆。研究同时测量功能通过率、漏洞率、安全警告率和记忆引用率，并比较显式安全提示及写入前过滤器的缓解效果。","method_example":"论文给出的偏好模式之一，是要求以后用 random.randint(1, 100) 生成会话标识。该写法可能让当前示例更容易运行，却会把可预测、取值空间很小的随机数模式保存为长期偏好。后续遇到新的会话管理任务时，模型可能继续套用这一模式。研究据此比较无记忆、写入风险记忆、加入安全要求和写入前过滤等条件下生成代码的安全性。","evidence":"作者报告，在 5 种编程语言上，加入不安全偏好记忆后漏洞率上升 2.7—50.3 个百分点，而不少场景中的功能正确性反而提高。显式安全要求可使漏洞率下降 19.7—33.6 个百分点，但最多损失 15.9 个百分点的功能通过率。两个大语言模型过滤器在 57 条已标注风险记忆上均检出了全部风险项。","limitations":"闭源服务的模型和策略可能随时间变化；每个输入只生成 3 个样本；风险记忆由研究者从已知不安全解法中提炼，可能比自然用户偏好更集中；过滤器结果来自规模较小、分布相近的标注集合，不能外推为通用保证。","practice":"代码助手的记忆写入应进入安全评审和审计轨迹，不能把用户偏好自动提升为跨项目的高信任规则。与其只在生成后扫描代码，更适合在长期记忆写入前识别、提示和阻断风险模式。","recommendation":"论文同时考察安全和功能效用，揭示了“代码更容易通过测试，但安全性反而下降”的危险错觉，对集成开发环境和编程智能体的记忆设计有直接参考价值。"},"primary_url":"https://arxiv.org/abs/2607.17619"},{"id":"arxiv-2607-16487-fuzz-emup","title":"Fuzz'EMup: Leveraging EM Side-Channel Emanation to Guide Black-Box Embedded Firmware Fuzzing","normalized_title":"fuzz emup leveraging em side channel emanation to guide black box embedded firmware fuzzing","authors":["Fatemeh Moradihaghighi","Zihao Zhan","Yanan Guo","Ziming Zhao","Mashrur Chowdhury","Zhenkai Zhang"],"venues":["arXiv"],"status":"preprint-unreviewed","doi":null,"arxiv_id":"2607.16487","urls":["https://arxiv.org/abs/2607.16487"],"first_seen":"2026-07-21","last_updated":"2026-07-21","topics":["application-security","embedded-security","firmware-fuzzing","em-side-channel"],"weekly_notes":["weekly/2026/2026-W30.md"],"week":"2026-W30","theme":"systems-security","theme_label":"系统、固件与侧信道","cached":true,"details":{"cache_path":"weekly/2026/2026-W30.md","week":"2026-W30","direction":"应用安全 / 嵌入式固件安全","keywords":"黑盒模糊测试、电磁侧信道、固件覆盖反馈、执行轨迹、微控制器","author_affiliations":"克莱姆森大学：Fatemeh Moradihaghighi、Mashrur Chowdhury、Zhenkai Zhang；得克萨斯理工大学：Zihao Zhan；罗切斯特大学：Yanan Guo；美国东北大学：Ziming Zhao","venue_status":"arXiv｜预印","public_date":"2026-07-18 04:25（北京时间）公开","original_links":[{"label":"arXiv 原文","url":"https://arxiv.org/abs/2607.16487"}],"question":"许多嵌入式设备无法提取固件、插入覆盖探针或稳定重宿主，传统覆盖引导模糊测试因此失去最重要的反馈信号。纯随机黑盒测试又很难判断一个新输入是否触发了新的执行路径。论文研究能否从微控制器运行时产生的电磁辐射中提取近似覆盖反馈，并用它指导输入选择和种子调度。","method":"作者先比较设备活动和空闲状态，选择最能反映执行差异的频段；随后用动态时间规整对齐存在抖动的电磁轨迹，检测轨迹持续分叉的位置；最后按分叉时间组织执行树，减少每条新轨迹与全部历史轨迹逐一比较的成本，并把有新颖分叉的输入优先放回模糊测试队列。","method_example":"向同一固件发送两个串口输入后，示波器采集到的电磁波形前半段相似，但其中一个输入在某个时间点开始持续偏离，可能意味着程序进入了不同分支。系统先对齐两个波形以消除时序抖动，再把持续分叉记为新的执行特征，并提高该输入作为后续变异种子的优先级，而不需要读取固件内部覆盖计数器。","evidence":"论文在同一 STM32L476RG 微控制器上运行 GPS、步进电机、数控设备和焊台四个真实固件。硬件执行阶段只使用电磁信号反馈，再在自建 QEMU 板级模型中重放输入以统计真实覆盖。电磁引导方法在四个目标上覆盖更多指令，覆盖新颖性的命中率提高 1.19—2.58 倍，并以更少输入达到随机基线的最终覆盖水平。","limitations":"四个目标均移植到同一微控制器并通过串口测试，尚未验证实时操作系统、网络协议、不同封装和现场噪声；QEMU 重放与物理执行可能存在语义偏差；论文展示的是覆盖提升而非新漏洞，且没有充分报告多次独立硬件实验的置信区间。","practice":"该方法适合“拿不到固件但能重复输入”的硬件实验室评估。实际使用仍需把电磁轨迹新颖性与崩溃、超时和外部状态异常等判定信号结合，并计入采样设备和轨迹对齐带来的吞吐成本。","recommendation":"把物理侧信道转化为黑盒固件测试反馈，思路新颖且与物联网设备安全直接相关；现有证据更适合支持可行性，而不能直接证明漏洞发现能力。 ISSTA 2026 官方接收论文列表已确认以下题目，但截至本次检索仍缺少足够的公开摘要或全文，因此暂不根据题目推断方法和实验： 统一状态来源：ISSTA 2026 官方接收论文列表。待公开摘要、正式论文链接或作者预印本后再评估；若已有预印本条目，则更新原条目而不重复新增。"},"primary_url":"https://arxiv.org/abs/2607.16487"},{"id":"arxiv-2607-14611-bad-memory","title":"Bad Memory: Evaluating Prompt Injection Risks from Memory in Agentic Systems","normalized_title":"bad memory evaluating prompt injection risks from memory in agentic systems","authors":["Soham Gadgil","David Alexander","Sai Sunku","Franziska Roesner"],"venues":["arXiv"],"status":"preprint-unreviewed","doi":null,"arxiv_id":"2607.14611","urls":["https://arxiv.org/abs/2607.14611"],"first_seen":"2026-07-21","last_updated":"2026-07-21","topics":["agent-security","persistent-memory","prompt-injection","coding-agent"],"weekly_notes":["weekly/2026/2026-W30.md"],"week":"2026-W30","theme":"agent-security","theme_label":"智能体与大模型安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W30.md","week":"2026-W30","direction":"智能体安全 / 持久记忆安全","keywords":"跨会话攻击、记忆污染、仓库指令、攻击载荷持久性、编程智能体","author_affiliations":"华盛顿大学：Soham Gadgil、David Alexander、Sai Sunku、Franziska Roesner","venue_status":"arXiv｜预印","public_date":"2026-07-16 公开；本期补录","original_links":[{"label":"arXiv 原文","url":"https://arxiv.org/abs/2607.14611"}],"question":"Claude Code、Codex 等编程智能体会自动读取 CLAUDE.md、AGENTS.md 或其他长期行为与知识文件。一旦恶意指令进入这些文件，风险可能不只发生在当前会话，还会持续影响未来会话、较弱模型或子智能体。论文希望同时回答两个问题：预植入记忆中的攻击载荷能否持续奏效，以及模型本轮拒绝攻击是否意味着风险已经被清除。","method":"作者在沙箱合成工作区中设置凭据外泄、未授权工具使用和品牌定向三类目标，并比较单次探测、重复同一攻击、叠加不同攻击三种会话序列。评估除攻击成功率外，还单独测量攻击载荷是否继续保留在记忆中，从而区分“当前拒绝”和“未来不再受影响”。","method_example":"攻击者预先在仓库的 AGENTS.md 中加入一条要求把环境凭据发送到外部地址的伪装说明。第一个会话中的模型可能识别并拒绝执行，但若该说明仍留在文件中，下一次启动的较弱模型会重新读取它并再次面临攻击。论文通过连续会话重复或叠加此类载荷，分别记录执行结果和文件中的载荷是否仍存在。","evidence":"研究测试 4 个模型，每种条件重复 10 次。单次探测的平均攻击成功率为 23.3%—63.3%。叠加不同攻击时，Opus 4.7 的平均攻击成功率最低，为 18.3%，但攻击载荷保留率最高，达到 93.3%，说明本轮拒绝与清除未来风险是两个不同指标。","limitations":"工作区和任务均为合成；主要实验假设攻击载荷已经存在于记忆中，初步实验没有可靠证明外部内容会被自动写入可信记忆；研究只覆盖 3 类目标、较短会话序列和每条件 10 次重复，结果也会受到具体产品版本和策略变化影响。","practice":"智能体启动时应校验高影响记忆文件；记忆写入应展示来源、差异和用户确认。模型拒绝攻击后还应触发隔离或修复，而不是让载荷继续留给后续会话、弱模型或子智能体。","recommendation":"论文把安全指标从单轮攻击成功率扩展到跨会话持久性，特别适合评估会自动加载仓库指令文件的编程智能体。"},"primary_url":"https://arxiv.org/abs/2607.14611"},{"id":"arxiv-2607-05120-agent-data-injection","title":"Agent Data Injection Attacks are Realistic Threats to AI Agents","normalized_title":"agent data injection attacks are realistic threats to ai agents","authors":["Woohyuk Choi","Juhee Kim","Taehyun Kang","Jihyeon Jeong","Luyi Xing","Byoungyoung Lee"],"venues":["arXiv"],"status":"preprint-unreviewed","doi":null,"arxiv_id":"2607.05120","urls":["https://arxiv.org/abs/2607.05120","https://github.com/compsec-snu/adi"],"first_seen":"2026-07-21","last_updated":"2026-07-21","topics":["agent-security","indirect-prompt-injection","data-integrity","web-agent","coding-agent"],"weekly_notes":["weekly/2026/2026-W30.md"],"week":"2026-W30","theme":"agent-security","theme_label":"智能体与大模型安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W30.md","week":"2026-W30","direction":"智能体安全 / 可信数据边界","keywords":"数据注入、网页智能体、编程智能体、结构伪造、信息流","author_affiliations":"首尔大学：Woohyuk Choi、Juhee Kim、Taehyun Kang、Byoungyoung Lee；Largosoft：Jihyeon Jeong；伊利诺伊大学厄巴纳—香槟分校：Luyi Xing","venue_status":"arXiv｜预印","public_date":"2026-07-06 公开；本期补录","original_links":[{"label":"arXiv 原文","url":"https://arxiv.org/abs/2607.05120"}],"question":"现有防御通常试图区分“可信指令”和“不可信文本”，但智能体上下文中还包含作者身份、网页元素编号、工具调用记录等结构化数据。即使模型不把网页正文当作指令，它仍可能把攻击者控制的数据误认成可信元数据。论文要说明这种数据边界混淆是否形成独立于传统提示注入的攻击面，并评估现有信息流防御为什么仍可能失效。","method":"论文提出智能体数据注入攻击，并利用概率分隔符注入，让经过转义或格式化后的攻击文本仍可能被模型解释为结构边界。作者在网页智能体和编程智能体中构造任意点击、伪造来源诱导命令执行、伪造工具结果触发供应链风险等场景，并扩展 AgentDojo 基准以比较传统提示注入与数据注入。","method_example":"网页智能体通常会把页面内容整理成带元素编号的文本，再要求模型选择要点击的编号。攻击页面可以在普通内容中嵌入近似系统分隔符和伪造编号，让模型误以为攻击者写入的按钮是可信解析器生成的元素。论文方法通过多种分隔符变体反复测试这种结构混淆，并观察智能体是否点击攻击者指定对象。","evidence":"在 6 个模型、157 个 JSON 和网页文档对象模型测试用例上，作者报告 JSON 场景攻击成功率为 31.3%—43.3%，网页场景为 33.3%—100%。扩展后的 AgentDojo 包含 96 个用户任务、108 个数据注入攻击和 935 个传统提示注入；所测防御把传统注入压到 0—0.7%，但数据注入仍最高达到 50%。只有严格信息流方案把数据注入降为 0%，同时正常任务效用降至 36.5%。","limitations":"攻击通常假设对手知道或能恢复智能体使用的数据格式；闭源服务的内部格式未必能稳定提取；智能体层评估只使用 GPT-5.2；真实产品中的确认对话框、版本变化和厂商修复会影响攻击效果。","practice":"工具返回值应尽量采用带类型对象或不透明句柄，而不是直接拼接文本。可信元数据与用户内容需要保持不可伪造的来源标记，敏感工具调用还应由独立策略执行器再次验证。","recommendation":"论文指出“指令与数据分离”仍不够细，智能体数据内部同样需要字段级的信任和完整性边界，适合安全架构和工具协议设计者阅读。"},"primary_url":"https://arxiv.org/abs/2607.05120"},{"id":"arxiv-2607-18063-adaptive-adversaries","title":"Adaptive Adversaries: A Multi-Turn, Multi-LLM Benchmark for LLM Agent Security","normalized_title":"adaptive adversaries a multi turn multi llm benchmark for llm agent security","authors":["Devina Jain","David Hartmann","Chuan Li"],"venues":["arXiv","Second Workshop on Agents in the Wild: Safety, Security, and Beyond (author-stated)"],"status":"preprint-unreviewed","doi":null,"arxiv_id":"2607.18063","urls":["https://arxiv.org/abs/2607.18063"],"first_seen":"2026-07-21","last_updated":"2026-07-21","topics":["agent-security","adaptive-red-teaming","benchmark","prompt-injection"],"weekly_notes":["weekly/2026/2026-W30.md"],"week":"2026-W30","theme":"agent-security","theme_label":"智能体与大模型安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W30.md","week":"2026-W30","direction":"智能体安全 / 自适应红队评测","keywords":"多轮攻击、多模型评测、自适应对手、攻击成功率、结果判定","author_affiliations":"Lambda：Devina Jain、David Hartmann、Chuan Li","venue_status":"arXiv｜预印","public_date":"2026-07-20 公开","original_links":[{"label":"arXiv 原文","url":"https://arxiv.org/abs/2607.18063"}],"question":"许多安全基准使用固定攻击提示，并只统计一次交互中的成功率，但现实攻击者会观察拒绝理由、调整措辞和更换策略。固定攻击池可能低估模型经过多轮试探后暴露的弱点，单一攻击模型和总攻击成功率也可能掩盖场景差异。论文因此研究多轮、自适应、多攻击模型评测会如何改变对智能体安全性的判断。","method":"作者设计了 21 个攻击场景组成的攻击者—防御者协议。攻击模型最多调整 15 轮，每一轮的防御回答则作为新的无记忆交互进行评估，并用结构化结果检查器判断攻击是否真正达成目标。项目还提供场景、编排器、命令行工具、交互记录和重放数据。","method_example":"在固定评测中，一条越权请求被拒绝后就记为防御成功；在该论文的协议中，攻击模型会读取拒绝回答，下一轮可能把同一目标拆成看似无害的子任务、改变角色设定或利用前一轮暴露的策略边界。系统持续记录每轮尝试，并由结果检查器判断是否真的发生越权行为，而不是只根据回答语气判断。","evidence":"3 个攻击模型与 3 个防御模型组成 945 场对抗。只计算第一轮时，攻击成功率为 0—1%；允许 15 轮自适应后上升至 5.4%—14%。合并 3 个攻击模型发现的独特成功攻击，比最佳单一攻击模型多 1.4—2.2 倍。21 个场景中有 13 个能区分至少一对防御模型，但场景间排名一致性较低，Kendall 协调系数为 0.19。","limitations":"每个组合只有 5 次重复，置信区间较宽；21 个场景经过难度校准，并非生产任务的随机样本；防御模型不保留跨轮记忆，与真实有状态智能体不同；闭源接口变化也会降低逐词元复现能力。","practice":"智能体安全回归测试应加入实时自适应攻击者、多个攻击模型、场景级结果和基于实际结果的判定器，不能只依赖静态越狱集合或汇总攻击成功率。","recommendation":"论文提供了可执行的红队评测设计，适合用来改造内部测试流水线；但样本规模决定了它更适合作为评测框架，而不是模型安全排行榜。"},"primary_url":"https://arxiv.org/abs/2607.18063"},{"id":"usenix-sec26-jannett-passkeys","title":"The State of Passkeys: Studying the Adoption and Security of Passkeys on the Web","normalized_title":"the state of passkeys studying the adoption and security of passkeys on the web","authors":["Louis Jannett","Andreas Mayer","Maximilian Westers","Vladislav Mladenov","Christian Mainka","Jorg Schwenk"],"venues":["USENIX Security 2026"],"status":"accepted-prepublication","doi":null,"arxiv_id":null,"urls":["https://www.usenix.org/conference/usenixsecurity26/presentation/jannett"],"first_seen":"2026-07-17","last_updated":"2026-07-17","topics":["application-security","passkeys","webauthn","authentication"],"weekly_notes":["weekly/2026/2026-W29.md"],"week":"2026-W29","theme":"mobile-security","theme_label":"移动与身份安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W29.md","week":"2026-W29","direction":"应用安全 / 身份认证 / WebAuthn","author_affiliations":"Louis Jannett 等（Ruhr University Bochum、Heilbronn University of Applied Sciences、University of Wuppertal）","venue_status":"USENIX Security ’26，已接收；会前版本可用","original_links":[{"label":"官方页面","url":"https://www.usenix.org/conference/usenixsecurity26/presentation/jannett"}],"question":"Passkey 在真实网站的采用情况及其 WebAuthn 实现是否安全。","method":"PASSKEYS-RADAR 汇聚社区目录、Tranco、CrUX 和历史网页数据；PASSKEYS-ATTACKER 可操纵 WebAuthn 各阶段消息并实现 15 类攻击测试。","evidence":"作者分析 872 个启用 Passkey 的网站，并在 103 个网站上评估攻击；18 个网站存在两类关键严重度风险，53 个至少存在一类高严重度风险，影响包括账户接管、删除 Passkey、锁定和会话固定。","limitations":"扫描是时间截面，网站可能已修复；CVSS 严重度和实际可利用条件不完全等价，测试站点也不是全体部署的随机样本。","recommendation":"说明“采用抗钓鱼标准”并不自动等于安全，实现、生命周期管理和恢复流程同样关键。"},"primary_url":"https://www.usenix.org/conference/usenixsecurity26/presentation/jannett"},{"id":"usenix-sec26-kim-agentic","title":"SoK: Attack and Defense Landscape of Agentic AI Systems","normalized_title":"sok attack and defense landscape of agentic ai systems","authors":["Juhee Kim","Wenbo Guo","Dawn Song"],"venues":["USENIX Security 2026"],"status":"accepted-prepublication","doi":null,"arxiv_id":null,"urls":["https://www.usenix.org/conference/usenixsecurity26/presentation/kim-juhee-agentic"],"first_seen":"2026-07-17","last_updated":"2026-07-17","topics":["agent-security","systematization-of-knowledge"],"weekly_notes":["weekly/2026/2026-W29.md"],"week":"2026-W29","theme":"agent-security","theme_label":"智能体与大模型安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W29.md","week":"2026-W29","direction":"智能体安全 / SoK","author_affiliations":"Juhee Kim（UC Berkeley、首尔大学），Wenbo Guo（UC Santa Barbara），Dawn Song（UC Berkeley）","venue_status":"USENIX Security ’26，已接收；会前版本可用","original_links":[{"label":"官方页面","url":"https://www.usenix.org/conference/usenixsecurity26/presentation/kim-juhee-agentic"}],"question":"如何统一描述 Agentic AI 的设计空间、攻击面与防御机制。","method":"论文给出系统化知识框架，并总结智能体组合 LLM 与非 AI 工具后产生的独特风险及开放问题。","evidence":"SoK 的主要价值是分类和综合，而非提出单一攻击或防御并做统一基准实验。","limitations":"智能体技术演化快，分类体系可能很快需要扩展；“首个全面框架”是作者主张，应结合其纳入标准和遗漏范围评估。","recommendation":"适合作为后续周报的概念底座，用来判断新论文究竟覆盖模型、记忆、工具、权限还是多智能体传播层。"},"primary_url":"https://www.usenix.org/conference/usenixsecurity26/presentation/kim-juhee-agentic"},{"id":"usenix-sec26-chen-vulgenie","title":"Patch-Guided Vulnerability Detection: Extracting Java API Security Rules via Attack–Defense Cross-Analysis","normalized_title":"patch guided vulnerability detection extracting java api security rules via attack defense cross analysis","authors":["Bofei Chen","Shuang Liao","Lei Zhang","Chibin Zhang","Mathias Payer","Yuan Zhang"],"venues":["USENIX Security 2026"],"status":"accepted-prepublication","doi":null,"arxiv_id":null,"urls":["https://www.usenix.org/conference/usenixsecurity26/presentation/chen-bofei"],"first_seen":"2026-07-17","last_updated":"2026-07-17","topics":["application-security","program-analysis","java","api-misuse","patch-mining"],"weekly_notes":["weekly/2026/2026-W29.md"],"week":"2026-W29","theme":"application-security","theme_label":"应用与协议安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W29.md","week":"2026-W29","direction":"应用安全 / 程序分析 / Java API 误用","author_affiliations":"Bofei Chen、Shuang Liao、Lei Zhang、Yuan Zhang（复旦大学），Chibin Zhang、Mathias Payer（EPFL）","venue_status":"USENIX Security ’26，已接收；会前版本可用","original_links":[{"label":"官方页面","url":"https://www.usenix.org/conference/usenixsecurity26/presentation/chen-bofei"}],"question":"能否从已确认安全补丁中抽取精确 API 安全规则，再发现其他应用中的同类误用。","method":"VulGenie 使用补丁图隔离约束与防御修改，通过攻防交叉验证合成规则，并以偏差引导静态分析扩展检测。","evidence":"在 150 个近期 Java 安全补丁上抽取 198 条规则，作者报告精度 81.82%，其中 177 条未被 CodeQL 覆盖；在 10 个流行 Java 应用中发现 46 个零日漏洞，25 个已修复并获分配 10 个 CVE。","limitations":"评估规模和项目选择影响外部有效性；“CodeQL 未覆盖”不代表 CodeQL 无法通过新规则覆盖，零日确认程度需结合披露与补丁核验。","recommendation":"把补丁知识自动转化为可执行检测规则，连接软件工程中的补丁挖掘与应用安全中的可扩展漏洞发现。"},"primary_url":"https://www.usenix.org/conference/usenixsecurity26/presentation/chen-bofei"},{"id":"usenix-sec26-merget-opossum","title":"Opossum Attack: Application Layer Desynchronization using Opportunistic TLS","normalized_title":"opossum attack application layer desynchronization using opportunistic tls","authors":["Robert Merget","Nurullah Erinola","Marcel Maehren","Lukas Knittel","Sven Hebrok","Marcus Brinkmann","Juraj Somorovsky","Jorg Schwenk"],"venues":["USENIX Security 2026"],"status":"accepted-prepublication","doi":null,"arxiv_id":null,"urls":["https://www.usenix.org/conference/usenixsecurity26/presentation/merget"],"first_seen":"2026-07-17","last_updated":"2026-07-17","topics":["application-security","tls","protocol-security","desynchronization"],"weekly_notes":["weekly/2026/2026-W29.md"],"week":"2026-W29","theme":"application-security","theme_label":"应用与协议安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W29.md","week":"2026-W29","direction":"应用层协议安全 / TLS / Web 安全","author_affiliations":"Robert Merget 等（Technology Innovation Institute、Ruhr University Bochum、Paderborn University）","venue_status":"USENIX Security ’26，已接收；会前版本可用","original_links":[{"label":"官方页面","url":"https://www.usenix.org/conference/usenixsecurity26/presentation/merget"}],"question":"同时支持隐式 TLS 与机会式 TLS 时，协议升级语义能否导致请求—响应错位并破坏认证。","method":"论文提出不依赖具体实现 Bug 的应用层反同步攻击，并详细分析 HTTP 的四类利用方向。","evidence":"IPv4 范围扫描发现超过 300 万服务器同时支持相关模式；HTTP 场景中发现 20,121 台服务器在 35 个端口支持机会式 HTTP，其中 2,268 台也支持 HTTPS，539 台使用相同域名，构成作者定义的可利用场景。","limitations":"暴露面数字不等于已确认成功利用；真实攻击仍依赖网络中间人位置、客户端/服务器行为及部署配置。","recommendation":"提醒工程团队：即使 TLS 算法和实现本身现代且正确，协议组合与状态机语义仍会破坏认证保证。 以下论文已出现在 USENIX Security ’26 官方技术议程，但截至本次检索，官方页面仅公开题目/作者或正文仍待大会首日发布，因此不对方法与结果作推断： 这是仓库首次运行，papers/index.jsonl 此前为空，因此没有历史重复项。后续周报将以本期 8 篇为基线；若预印本出现正式 DOI 或论文更新版本，将更新现有条目而不重复新增。"},"primary_url":"https://www.usenix.org/conference/usenixsecurity26/presentation/merget"},{"id":"usenix-sec26-jeong-network-agent","title":"Network-Level Prompt and Trait Leakage in Local Research Agents","normalized_title":"network level prompt and trait leakage in local research agents","authors":["Hyejun Jeong","Mohammadreza Teymoorianfard","Abhinav Kumar","Amir Houmansadr","Eugene Bagdasarian"],"venues":["USENIX Security 2026"],"status":"accepted-prepublication","doi":null,"arxiv_id":null,"urls":["https://www.usenix.org/conference/usenixsecurity26/presentation/jeong"],"first_seen":"2026-07-17","last_updated":"2026-07-17","topics":["agent-security","privacy","network-side-channel"],"weekly_notes":["weekly/2026/2026-W29.md"],"week":"2026-W29","theme":"agent-security","theme_label":"智能体与大模型安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W29.md","week":"2026-W29","direction":"智能体隐私 / 网络侧信道","author_affiliations":"Hyejun Jeong、Mohammadreza Teymoorianfard、Abhinav Kumar、Amir Houmansadr、Eugene Bagdasarian（马萨诸塞大学阿默斯特分校）","venue_status":"USENIX Security ’26，已接收；会前版本可用","original_links":[{"label":"官方页面","url":"https://www.usenix.org/conference/usenixsecurity26/presentation/jeong"}],"question":"被动网络观察者能否仅凭访问 IP/域名及时间模式，推断本地 Web/Research Agent 的用户问题和长期用户特征。","method":"论文构建真实与合成人物查询的流量数据集，并提出 OBELS 指标衡量原始提示与推断提示在功能和领域知识上的相似度。","evidence":"研究智能体每个请求访问约 70—140 个域；作者报告攻击可恢复超过 73% 的提示功能/领域知识，多会话下最多恢复 32 个潜在特征中的 19 个；限制域多样性或混淆流量使攻击效果平均降低 29%，且作者称效用影响很小。","limitations":"指标与“恢复百分比”不等同于逐字重建；效果对代理策略、缓存、加密 DNS、网络路径和用户行为分布敏感。","recommendation":"对“本地运行即隐私安全”的直觉形成重要反例，也直接影响自动研究、搜索与企业情报智能体的部署架构。"},"primary_url":"https://www.usenix.org/conference/usenixsecurity26/presentation/jeong"},{"id":"usenix-sec26-wang-masleak","title":"MASLeak: Investigating and Exposing Intellectual Property Leakage Vulnerabilities in Multi-Agent Systems","normalized_title":"masleak investigating and exposing intellectual property leakage vulnerabilities in multi agent systems","authors":["Liwen Wang","Wenxuan Wang","Shuai Wang","Zongjie Li","Zhenlan Ji","Zongyi Lyu","Daoyuan Wu","Shing-Chi Cheung"],"venues":["USENIX Security 2026"],"status":"accepted-prepublication","doi":null,"arxiv_id":null,"urls":["https://www.usenix.org/conference/usenixsecurity26/presentation/wang-liwen"],"first_seen":"2026-07-17","last_updated":"2026-07-17","topics":["multi-agent-security","ip-leakage","black-box-attack"],"weekly_notes":["weekly/2026/2026-W29.md"],"week":"2026-W29","theme":"agent-security","theme_label":"智能体与大模型安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W29.md","week":"2026-W29","direction":"多智能体安全 / 知识产权泄漏","author_affiliations":"Liwen Wang 等（香港科技大学、中国人民大学、岭南大学）","venue_status":"USENIX Security ’26，已接收；会前版本可用","original_links":[{"label":"官方页面","url":"https://www.usenix.org/conference/usenixsecurity26/presentation/wang-liwen"}],"question":"仅通过公开 API，攻击者能否黑盒恢复多智能体系统的拓扑、系统提示、任务指令和工具用法。","method":"MASLEAK 借鉴蠕虫传播思路构造恶意查询，使泄漏内容在智能体间被诱导、传播并保留；作者还构建了 810 个合成多智能体应用的数据集，并测试 Coze、CrewAI 等真实系统。","evidence":"作者报告多数场景下系统提示与任务指令提取成功率平均 87%，系统架构提取成功率 92%。","limitations":"合成应用与真实生产编排的差距需要进一步审查；成功率依赖攻击目标、输出可观测性与后端模型，不能直接外推到所有 MAS。","recommendation":"把“提示泄漏”提升到系统架构与协作协议层，直接关联 Agent 平台的商业机密保护和最小披露设计。"},"primary_url":"https://www.usenix.org/conference/usenixsecurity26/presentation/wang-liwen"},{"id":"usenix-sec26-liu-ios","title":"Cracks in the Walled Garden: Dissecting the Gray-Market of Unauthorized iOS App Distribution via Ad Hoc Sideloading","normalized_title":"cracks in the walled garden dissecting the gray market of unauthorized ios app distribution via ad hoc sideloading","authors":["Yijing Liu","Yiming Zhang","Baojun Liu","Haixin Duan"],"venues":["USENIX Security 2026"],"status":"accepted-prepublication","doi":null,"arxiv_id":null,"urls":["https://www.usenix.org/conference/usenixsecurity26/presentation/liu-yijing"],"first_seen":"2026-07-17","last_updated":"2026-07-17","topics":["mobile-security","ios","sideloading","software-supply-chain"],"weekly_notes":["weekly/2026/2026-W29.md"],"week":"2026-W29","theme":"mobile-security","theme_label":"移动与身份安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W29.md","week":"2026-W29","direction":"iOS 安全 / 应用分发 / 供应链","author_affiliations":"Yijing Liu、Yiming Zhang、Baojun Liu、Haixin Duan（清华大学、BNRist）","venue_status":"USENIX Security ’26，已接收；会前版本可用","original_links":[{"label":"官方页面","url":"https://www.usenix.org/conference/usenixsecurity26/presentation/liu-yijing"}],"question":"Ad Hoc provisioning 如何演化为绕过 App Store 审核的灰色分发产业链。","method":"以用户视角收集并分析签名站点、签名工具和 .ipa 分发样本，反向工程证书流通与应用修改手法。","evidence":"作者识别 3,359 个活跃签名站点，逆向 12 个签名工具，获得 8,216 个 .ipa 条目，并报告证书转售利润率最高达 3,000%；大量样本是注入动态库的正版 App 修改版。","limitations":"研究重点是中国市场，地域和时间外推需谨慎；样本发现渠道可能遗漏封闭社群，风险类别也不代表每个样本都已被证实恶意。","recommendation":"将单个恶意 App 问题扩展到证书、工具、分发站与修改包构成的供应链，适合移动应用风控和平台治理研究。"},"primary_url":"https://www.usenix.org/conference/usenixsecurity26/presentation/liu-yijing"},{"id":"usenix-sec26-vlummens-bridges","title":"Bridges to Self: Silent Web-to-App Tracking on Mobile via Localhost","normalized_title":"bridges to self silent web to app tracking on mobile via localhost","authors":["Tim Vlummens","Aniketh Girish","Nipuna Weerasekara","Frederik Zuiderveen Borgesius","Gunes Acar","Narseo Vallina-Rodriguez"],"venues":["USENIX Security 2026"],"status":"accepted-prepublication","doi":null,"arxiv_id":null,"urls":["https://www.usenix.org/conference/usenixsecurity26/presentation/vlummens"],"first_seen":"2026-07-17","last_updated":"2026-07-17","topics":["mobile-security","android","web-to-app-tracking","privacy"],"weekly_notes":["weekly/2026/2026-W29.md"],"week":"2026-W29","theme":"mobile-security","theme_label":"移动与身份安全","cached":true,"details":{"cache_path":"weekly/2026/2026-W29.md","week":"2026-W29","direction":"移动安全 / Web—App 隔离 / 隐私","author_affiliations":"Tim Vlummens 等（KU Leuven、IMDEA Networks、Radboud University）","venue_status":"USENIX Security ’26，已接收；会前版本可用","original_links":[{"label":"官方页面","url":"https://www.usenix.org/conference/usenixsecurity26/presentation/vlummens"}],"question":"网站能否利用 localhost 通道与原生 App 通信，把 Web Cookie 与长期原生标识符绑定。","method":"结合美国和欧盟视角的大规模网页抓取与 Android App 系统分析，刻画 HTTP(S)、WebSocket、WebRTC 等标准被用于跨上下文跟踪的机制，并分析浏览器修复与 Local Network Access 权限方案。","evidence":"作者报告 Meta 与 Yandex 曾使用这类桥接；该技术可绕过清 Cookie、无痕模式、广告 ID 重置、VPN 及工作/个人配置隔离，并指出 WebRTC 全局单播 IPv6 和 .local mDNS 仍可能形成旁路。","limitations":"生态修复持续变化，具体可利用性需结合当前浏览器和 App 版本复测；法律分析与技术结论应分开理解。","recommendation":"真实世界影响强，揭示“浏览器沙箱”和“App 沙箱”分别成立时，跨生态组合仍可能破坏隐私边界。"},"primary_url":"https://www.usenix.org/conference/usenixsecurity26/presentation/vlummens"}],"viewpoints":[{"id":"alibaba-skill-up","title":"阿里开源 skill-up：让 Agent Skill 可评测可回归","source":"阿里技术","published_at":"2026-07-23","url":"https://mp.weixin.qq.com/s/lTdRNB3vTJoU0nAPBkHNtw","topics":["Agent Skill","评测","CI"],"summary":"把 Skill 的质量预期写成声明式用例，并在本地和 CI 中跨引擎回放。","highlights":["用 expect 承担确定性硬检查，用 rule/script/agent judge 处理更复杂的判定。","支持多轮会话、工具调用断言和真实仓库上的重型端到端评测。","CI 负责环境与调度，评测框架负责用例语义、执行、证据和报告。"]},{"id":"alibaba-skill-architecture","title":"面向复杂业务场景的智能分析 Skills 架构设计与演进实践","source":"阿里技术","published_at":"2026-07-17","url":"https://mp.weixin.qq.com/s/mF3TyV_GzkBdoyYfK14fWQ","topics":["Skill 架构","知识工程","Context"],"summary":"从三轮重构中总结领域知识密集型 Skill 的组织、路由和持续维护方法。","highlights":["知识应尽量收拢并按需加载，避免照搬微服务式的碎片化分层。","稳定知识与高频变化知识分开管理，写入粒度和运行时读取粒度可以不同。","少选项、强信号、约束骨架但释放内容，并把 Token 经济性作为架构硬约束。"]},{"id":"tencent-agent-evaluation","title":"AI Agent & Skill 测评方案及落地实践","source":"腾讯技术工程","published_at":"2026-06-16","url":"https://mp.weixin.qq.com/s/PUbGqheJhFMmb6hGj1ZtOw","topics":["Agent 评测","Rubric","稳定性"],"summary":"以确定性、模型和人工三类评分器，覆盖 Agent 从结果到过程、安全与体验的完整测评。","highlights":["确定性评分器优先，Rubric 处理开放式语义，人工用于校准、诊断和高风险兜底。","评测覆盖功能正确性、过程质量、效率成本、鲁棒安全、体验对齐五个维度。","区分能力测评与回归测评，把已稳定掌握的能力沉淀为持续运行的回归门禁。"]},{"id":"long-horizon-agents-survey","title":"百页综述梳理 Long-Horizon Agents 最新进展","source":"Xiaoxi / 小红书","published_at":"2026-07-17","url":"https://www.xiaohongshu.com/explore/6a59efef0000000010026a8f","project_url":"https://github.com/RUC-NLPIR/Awesome-Long-Horizon-Agents","topics":["Long-Horizon Agent","Harness","综述"],"summary":"从外部 Harness Engineering 与内部 Model Optimization 的协同演化理解长程智能体。","highlights":["发展路径从 Prompt Engineering 扩展到 Context Engineering，再到 Runtime Harness。","Harness 包含工作流、上下文与记忆、工具/MCP/Skills、编排、Hooks 和验证。","应用覆盖软件工程、信息检索、Computer Use、多模态和通用智能体。"]}]};
